mapper.select:
SELECT T1.MAC as mac, T1.TIME as time, T1.RX_PACKETS as rxPackets, T1.TX_PACKETS as txPackets FROM TBL_HOST_NIC_FLOW AS T1 ,
(SELECT HOST_ID, MAX(TIME)-${duration} AS TIME from TBL_HOST_NIC_FLOW GROUP BY HOST_ID) AS T2
WHERE T1.HOST_ID = T2.HOST_ID AND T1.TIME = T2.TIME
AND T1.HOST_ID =${hostId}

    AND MAC =#{mac}

SELECT MAC as mac, TIME as time, RX_FLOW as rxFlow, RX_PACKETS as rxPackets, TX_PACKETS as txPackets, TX_FLOW as txFlow,
RX_DROP as rxDropCount, TX_DROP as txDropCount, HOST_ID as hostId, HOST_POOL_ID as hostPoolId, CLUSTER_ID as clusterId,
OP_GROUP_ID as operatorGroupId, OP_GROUP_CODE as operatorGroupCode, RX_ERR as rxErrCount, TX_ERR as txErrCount FROM TBL_HOST_NIC_FLOW


        AND MAC =#{mac}


        AND HOST_ID =${hostId}


        AND TIME BETWEEN ${startTime} AND ${endTime}



    ORDER BY ${sortField} ASC


    ORDER BY ${sortField} DESC

SELECT MAC as mac, TIME as time, RX_FLOW as rxFlow, RX_PACKETS as rxPackets, TX_PACKETS as txPackets, TX_FLOW as txFlow,
RX_DROP as rxDropCount, TX_DROP as txDropCount FROM TBL_HOST_NIC_FLOW
WHERE HOST_ID =${hostId}  AND TIME BETWEEN ${startTime} AND ${endTime}

    AND MAC =#{mac}

ORDER BY TIME ASC

SELECT  MAX(tdio.RX_FLOW + tdio.TX_FLOW) as flow,  tdio.HOST_ID as hostId from TBL_HOST_NIC_FLOW tdio
WHERE tdio.TIME=(SELECT MAX(TIME) FROM TBL_HOST_NIC_FLOW)-${duration}

    AND tdio.HOST_POOL_ID=${hostPoolId}


    AND tdio.CLUSTER_ID=${clusterId}


    AND tdio.OP_GROUP_CODE LIKE #{operatorGroupCode}

GROUP BY  tdio.HOST_ID

SELECT any(tem.HOST_ID) hostId,SUM(tem.rx_avg) + SUM(tem.tx_avg) flow, any(th.cluster_id) clusterId, any(th.host_pool_id) hostpoolId, any(th.name) hostName
FROM (SELECT HOST_ID, MAC, ROUND(AVG(RX_FLOW),2) rx_avg, ROUND(AVG(TX_FLOW),2) tx_avg from TBL_HOST_NIC_FLOW where  TIME BETWEEN ${startTime} AND ${endTime}

    AND HOST_POOL_ID =${hostPoolId}


    AND CLUSTER_ID=${clusterId}


    AND HOST_ID=${hostId}


    AND OP_GROUP_CODE LIKE #{operatorGroupCode}

GROUP BY HOST_ID, MAC
HAVING MAX(TIME) > ${endTime} - 241) as tem
,${@com.h3c.h3cloud.performance.monitor.service.mapper.base.clickhouseMapperConstant@TBL_HOST} th WHERE tem.HOST_ID = th.id
GROUP BY tem.HOST_ID
ORDER BY flow DESC

    LIMIT ${limit}

SELECT tdio.HOST_ID as hostId,SUM(RX_FLOW)+SUM(TX_FLOW) as flow,tdio.TIME time, any(TT.name) as hostName FROM TBL_HOST_NIC_FLOW tdio INNER JOIN ${@com.h3c.h3cloud.performance.monitor.service.mapper.base.clickhouseMapperConstant@TBL_HOST} TT ON tdio.HOST_ID=TT.id WHERE tdio.HOST_ID IN (${hostIds}) AND tdio.TIME BETWEEN ${startTime} AND ${endTime}
AND tdio.OP_GROUP_CODE LIKE #{operatorGroupCode}
GROUP BY tdio.HOST_ID, tdio.TIME ORDER BY tdio.TIME ASC
